rss.channel:
    Lucubrator
    https://stwalsh.github.io/lucubrator/
    A reader of the English poetry canon
    en
    {% for entry in entries[:20] %}


      {{ entry.passage_used.poet if entry.passage_used else entry.source }} — {{ entry.date }}
      https://stwalsh.github.io/lucubrator/entries/{{ entry.slug }}.html
      {{ entry.id }}
      {{ entry.timestamp }}
      {% for post in entry.posts %}{{ post }}{% if not loop.last %}

{% endif %}{% endfor %}{% if entry.passage_used and entry.passage_used.poet %} — {{ entry.passage_used.poet }}{% if entry.passage_used.poem_title %}, "{{ entry.passage_used.poem_title }}"{% endif %}{% endif %}

    {% endfor %}
